import React from 'react';
import { useNavigate } from "react-router-dom";

function Home() {
  const navigate = useNavigate();

  return (
    <div>
      <br />
      <button onClick={() => navigate('/register')}>
        Register
      </button>
      <br />
    </div>
  );
}

export default Home;
